const results = $.steps.searchExa.response.results || $.steps.searchExa.response.data || [];
const maxPages = $.input.maxPages || 5;
const pages = results.slice(0, maxPages).map((r, i) => ({
  index: i + 1,
  url: r.url || '',
  title: r.title || 'Page ' + (i + 1),
  snippet: (r.text || '').slice(0, 300)
})).filter(p => p.url.length > 0);

let summary = '';
pages.forEach(p => {
  summary += p.index + '. ' + p.title + ' - ' + p.url + '\n';
});

return { pages, pageCount: pages.length, summary };

const pages = $.steps.selectPages.output.pages;
const iterations = $.steps.crawlPages.response.iterations || [];

let allContent = '';
let successCount = 0;
let failCount = 0;

iterations.forEach((iter, i) => {
  const page = pages[i] || { url: 'Unknown', title: 'Unknown' };
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;

  allContent += '=== PAGE ' + (i + 1) + ': ' + page.title + ' ===\n';
  allContent += 'URL: ' + page.url + '\n';

  if (resp && resp.markdown) {
    successCount++;
    allContent += 'Content:\n' + resp.markdown.slice(0, 4000) + '\n\n';
  } else {
    failCount++;
    allContent += 'Status: Failed to scrape\n\n';
  }
});

return { allContent, successCount, failCount, totalPages: pages.length };

const d = $.steps.compileContent.output;
const goal = $.input.extractionGoal || 'Extract all relevant structured data, contacts, links, and key information';
const query = $.input.searchQuery;

let prompt = 'You are an autonomous web crawler and data extraction specialist. Analyze the following crawled pages and extract structured information.\n\n';
prompt += 'ORIGINAL SEARCH QUERY: ' + query + '\n';
prompt += 'EXTRACTION GOAL: ' + goal + '\n';
prompt += 'PAGES CRAWLED: ' + d.successCount + ' of ' + d.totalPages + '\n\n';
prompt += 'CRAWLED CONTENT:\n' + d.allContent + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract all data matching the extraction goal from every page\n';
prompt += '- Identify links, contacts, profiles, or entities discovered\n';
prompt += '- Cross-reference data between pages for completeness\n';
prompt += '- Flag any pages that need deeper crawling\n';
prompt += '- Organize findings in a clear structure\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "2-3 sentence overview of crawl results",\n';
prompt += '  "pagesAnalyzed": [\n';
prompt += '    { "pageNumber": 1, "url": "url", "title": "title", "dataFound": ["item1", "item2"], "linksDiscovered": ["link1"] }\n';
prompt += '  ],\n';
prompt += '  "extractedEntities": [\n';
prompt += '    { "name": "entity", "type": "person|company|profile|link", "source": "url", "details": "extra info" }\n';
prompt += '  ],\n';
prompt += '  "crossPageInsights": ["insight spanning multiple pages"],\n';
prompt += '  "suggestedNextCrawls": ["url to crawl next for more data"],\n';
prompt += '  "totalEntitiesFound": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, pagesAnalyzed: [], extractedEntities: [], crossPageInsights: [], suggestedNextCrawls: [], totalEntitiesFound: 0 }; }

const ai = $.steps.parseAI.output;
const stats = $.steps.compileContent.output;
const query = $.input.searchQuery;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Autonomous AI Crawler Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Query:*\n' + query },
  { type: 'mrkdwn', text: '*Pages Crawled:*\n' + stats.successCount + '/' + stats.totalPages }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Entities Found:*\n' + (ai.totalEntitiesFound || 0) },
  { type: 'mrkdwn', text: '*Failed:*\n' + stats.failCount }
] });
blocks.push({ type: 'divider' });

const summary = (ai.summary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summary } });

if (ai.extractedEntities && ai.extractedEntities.length > 0) {
  blocks.push({ type: 'divider' });
  let entityText = '*Extracted Entities:*\n';
  ai.extractedEntities.slice(0, 10).forEach((e, i) => {
    entityText += (i + 1) + '. *' + (e.name || 'N/A') + '* (' + (e.type || 'unknown') + ')';
    if (e.details) entityText += ' - ' + e.details;
    entityText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: entityText.slice(0, 1800) } });
}

if (ai.pagesAnalyzed && ai.pagesAnalyzed.length > 0) {
  blocks.push({ type: 'divider' });
  let pageText = '*Pages Analyzed:*\n';
  ai.pagesAnalyzed.slice(0, 5).forEach((p, i) => {
    pageText += (i + 1) + '. <' + (p.url || '#') + '|' + (p.title || 'Page') + '> - ' + ((p.dataFound || []).length) + ' items found\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: pageText.slice(0, 1800) } });
}

if (ai.crossPageInsights && ai.crossPageInsights.length > 0) {
  blocks.push({ type: 'divider' });
  let insightText = '*Cross-Page Insights:*\n';
  ai.crossPageInsights.slice(0, 5).forEach((ins, i) => { insightText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightText.slice(0, 1800) } });
}

if (ai.suggestedNextCrawls && ai.suggestedNextCrawls.length > 0) {
  blocks.push({ type: 'divider' });
  let nextText = '*Suggested Next Crawls:*\n';
  ai.suggestedNextCrawls.slice(0, 5).forEach((url, i) => { nextText += (i + 1) + '. ' + url + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: nextText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI | One CLI' }] });

const fallbackText = 'AI Crawler: ' + stats.successCount + ' pages crawled, ' + (ai.totalEntitiesFound || 0) + ' entities found - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallbackText };
